template_code:
Type Element = Enregistrement
Debut
    car  : Caractere;
    suiv : ^Element;
Fin;

Type Pile = Enregistrement
Debut
    sommet : ^Element;
Fin;

Procedure Init(Var P : Pile)
Debut
    P.sommet := NIL;
Fin;

Procedure Empiler(Var P : Pile, c : Caractere)
Var n : ^Element;
Debut
    n := allouer(taille(Element));
    n->car := c;
    n->suiv := P.sommet;
    P.sommet := n;
Fin;

Procedure Depiler(Var P : Pile, Var c : Caractere)
Var tmp : ^Element;
Debut
    tmp := P.sommet;
    c := tmp->car;
    P.sommet := tmp->suiv;
    liberer(tmp);
Fin;

Fonction EstVide(P : Pile) : Booleen
Debut
    Retourner(P.sommet = NIL);
Fin;

Fonction Correspond(o : Caractere, f : Caractere) : Booleen
Debut
    Si o = '(' Et f = ')' Alors Retourner(Vrai); FinSi
    Si o = '[' Et f = ']' Alors Retourner(Vrai); FinSi
    Si o = '{' Et f = '}' Alors Retourner(Vrai); FinSi
    Retourner(Faux);
Fin;

Algorithme ParenthesesValides;
Var
    S[5000] : Chaine;
    i : Entier;
    c, top : Caractere;
    P : Pile;
    ok : Booleen;
Debut
    Lire(S);
    Init(P);
    ok := Vrai;

    Pour i := 0 a Longueur(S) - 1 Faire
        c := S[i];
        // TODO: empiler les ouvrants
        // TODO: pour un fermant, verifier sommet + correspondance
    FinPour

    Si Non EstVide(P) Alors ok := Faux; FinSi

    Si ok Alors Ecrire("Valid"); Sinon Ecrire("Invalid"); FinSi
Fin.
